async def _gather_env_snapshot(self) -> str:
    """Gather a compact environment snapshot to eliminate early exploration turns.

    Returns a short text block with working directory, file listing,
    available languages, package managers, GPU, installed Python libraries,
    and extra CLI tools. On any failure, returns empty string so the agent
    falls back to normal exploration.
    """
    if self._session is None:
        return ""

    env = self._session.environment

    # Single compound command for efficiency — each section guarded by || true
    bootstrap_cmd = (
        "echo '@@PWD@@' && pwd && "
        "echo '@@LS@@' && ls -la /app/ 2>/dev/null && "
        "echo '@@LANG@@' && "
        "(python3 --version 2>&1 || echo 'python3: not found') && "
        "(gcc --version 2>&1 | head -1 || echo 'gcc: not found') && "
        "(g++ --version 2>&1 | head -1 || echo 'g++: not found') && "
        "(node --version 2>&1 || echo 'node: not found') && "
        "(java -version 2>&1 | head -1 || echo 'java: not found') && "
        "(rustc --version 2>&1 || echo 'rustc: not found') && "
        "(go version 2>&1 || echo 'go: not found') && "
        "echo '@@PKG@@' && "
        "(pip3 --version 2>&1 || echo 'pip3: not found') && "
        "(pip --version 2>&1 || echo 'pip: not found') && "
        "(apt-get --version 2>&1 | head -1 || echo 'apt-get: not found') && "
        "echo '@@MEM@@' && free -h 2>/dev/null | head -2 || true && "
        "echo '@@GPU@@' && "
        "(nvidia-smi --query-gpu=name,memory.total --format=csv,noheader 2>/dev/null || echo 'GPU: not available') && "
        "echo '@@DISK@@' && "
        "(df -h /app/ 2>/dev/null | tail -1 || echo 'disk: unknown') && "
        "echo '@@PYLIB@@' && "
        "python3 -c \""
        "import importlib.util; "
        "pkgs = ['numpy','scipy','matplotlib','pandas','sklearn','torch','tensorflow',"
        "'biopython','Bio','cv2','PIL','ffmpeg','playwright','statsmodels','seaborn',"
        "'sympy','networkx','requests','lxml','h5py','numba']; "
        "avail = [p for p in pkgs if importlib.util.find_spec(p) is not None]; "
        "print(','.join(avail) if avail else 'none')"
        "\" 2>/dev/null || echo 'pylib-check: failed' && "
        "echo '@@XTOOLS@@' && "
        "(ffmpeg -version 2>&1 | head -1 || echo 'ffmpeg: not found') && "
        "(git --version 2>&1 || echo 'git: not found') && "
        "(make --version 2>&1 | head -1 || echo 'make: not found') && "
        "(mips-linux-gnu-gcc --version 2>&1 | head -1 || echo 'mips-linux-gnu-gcc: not found') && "
        "(curl --version 2>&1 | head -1 || echo 'curl: not found') && "
        "(wget --version 2>&1 | head -1 || echo 'wget: not found') || true"
    )

    try:
        result = await asyncio.wait_for(
            env.exec(command=bootstrap_cmd, timeout_sec=20),
            timeout=25,
        )
    except Exception:
        return ""

    stdout = (result.stdout or "").strip()
    if not stdout:
        return ""

    # Parse sections
    sections = {}
    current_key = None
    current_lines: list[str] = []
    for line in stdout.split("\n"):
        if line.startswith("@@") and line.endswith("@@"):
            if current_key:
                sections[current_key] = "\n".join(current_lines)
            current_key = line.strip("@")
            current_lines = []
        else:
            current_lines.append(line)
    if current_key:
        sections[current_key] = "\n".join(current_lines)

    # Build compact snapshot
    parts = []
    if "PWD" in sections:
        parts.append(f"Working directory: {sections['PWD'].strip()}")
    if "LS" in sections:
        ls_lines = sections["LS"].strip().split("\n")
        if len(ls_lines) <= 1 or (len(ls_lines) == 2 and "total 0" in ls_lines[0]):
            parts.append("/app contents: (empty directory)")
        elif len(ls_lines) > 25:
            parts.append(
                f"/app contents ({len(ls_lines)} entries):\n"
                + "\n".join(ls_lines[:20])
                + f"\n... ({len(ls_lines) - 20} more files)"
            )
        else:
            parts.append(f"/app contents:\n{sections['LS'].strip()}")
    if "LANG" in sections:
        lang_lines = [
            l.strip()
            for l in sections["LANG"].strip().split("\n")
            if l.strip()
        ]
        parts.append("Available languages/tools: " + "; ".join(lang_lines))
    if "PKG" in sections:
        pkg_lines = [
            l.strip()
            for l in sections["PKG"].strip().split("\n")
            if l.strip()
        ]
        parts.append("Package managers: " + "; ".join(pkg_lines))
    if "MEM" in sections:
        mem = sections["MEM"].strip()
        if mem:
            parts.append(f"Memory: {mem}")
    if "GPU" in sections:
        gpu = sections["GPU"].strip()
        if gpu and gpu != "GPU: not available":
            parts.append(f"GPU: {gpu}")
        else:
            parts.append("GPU: not available")
    if "DISK" in sections:
        disk = sections["DISK"].strip()
        if disk and disk != "disk: unknown":
            parts.append(f"Disk (/app): {disk}")
    if "PYLIB" in sections:
        pylib = sections["PYLIB"].strip()
        if pylib and pylib not in ("none", "pylib-check: failed"):
            parts.append(f"Pre-installed Python packages: {pylib}")
    if "XTOOLS" in sections:
        xtools_lines = sections["XTOOLS"].strip().split("\n")
        found = [
            l.strip()
            for l in xtools_lines
            if l.strip() and "not found" not in l and l.strip()
        ]
        if found:
            parts.append("Extra tools: " + "; ".join(found))

    if not parts:
        return ""

    return "[Environment Snapshot]\n" + "\n".join(parts)
